"""Atuadores locais da Raspberry (GPIO real ou stub)."""

from __future__ import annotations

import logging
import platform

import config

logger = logging.getLogger("actuators")


class Actuators:
    def __init__(self) -> None:
        self.led = False
        self.buzzer = False
        self.relays = {"1": False, "2": False}
        self.servos = {"porta-1": 0, "porta-2": 0, "arm": 45}
        self.doors = {"main": False, "garage": False}
        self._gpio = None
        self._init_gpio()

    def _init_gpio(self) -> None:
        want = config.USE_GPIO
        machine = platform.machine().lower()
        is_pi = machine.startswith("arm") or machine.startswith("aarch64")
        enable = want == "true" or (want == "auto" and is_pi)
        if not enable:
            logger.info("GPIO desabilitado — modo simulação no agente.")
            return
        try:
            import RPi.GPIO as GPIO  # type: ignore

            GPIO.setmode(GPIO.BCM)
            GPIO.setwarnings(False)
            for pin in (config.PIN_LED, config.PIN_BUZZER, config.PIN_RELAY1, config.PIN_RELAY2):
                GPIO.setup(pin, GPIO.OUT)
                GPIO.output(pin, GPIO.LOW)
            self._gpio = GPIO
            logger.info("GPIO inicializado na Raspberry.")
        except Exception as exc:  # pragma: no cover
            logger.warning("Falha GPIO (%s). Continuando em stub.", exc)
            self._gpio = None

    def set_led(self, on: bool) -> None:
        self.led = on
        if self._gpio:
            self._gpio.output(config.PIN_LED, self._gpio.HIGH if on else self._gpio.LOW)
        logger.info("LED=%s", on)

    def set_buzzer(self, on: bool) -> None:
        self.buzzer = on
        if self._gpio:
            self._gpio.output(config.PIN_BUZZER, self._gpio.HIGH if on else self._gpio.LOW)
        logger.info("BUZZER=%s", on)

    def set_relay(self, channel: str, on: bool) -> None:
        channel = str(channel)
        self.relays[channel] = on
        if self._gpio:
            pin = config.PIN_RELAY1 if channel == "1" else config.PIN_RELAY2
            self._gpio.output(pin, self._gpio.HIGH if on else self._gpio.LOW)
        logger.info("RELAY %s=%s", channel, on)

    def set_servo(self, servo_id: str, angle: int) -> None:
        angle = max(0, min(180, int(angle)))
        self.servos[servo_id] = angle
        if servo_id == "porta-1":
            self.doors["main"] = angle >= 70
        elif servo_id == "porta-2":
            self.doors["garage"] = angle >= 70
        logger.info("SERVO %s=%s", servo_id, angle)

    def set_door(self, door_id: str, open_: bool) -> None:
        self.doors[door_id] = open_
        angle = 90 if open_ else 0
        if door_id == "main":
            self.servos["porta-1"] = angle
        elif door_id == "garage":
            self.servos["porta-2"] = angle
        logger.info("DOOR %s=%s", door_id, open_)

    def cleanup(self) -> None:
        if self._gpio:
            self._gpio.cleanup()

(() => {
  const $ = (sel) => document.querySelector(sel);
  const logList = $("#log-list");
  const expList = $("#exp-list");
  let ws;
  let reconnectTimer;
  let latencySeries = [];

  function pushLog(text) {
    const li = document.createElement("li");
    const ts = new Date().toLocaleTimeString();
    li.innerHTML = `<strong>${ts}</strong> — ${text}`;
    logList.prepend(li);
    while (logList.children.length > 40) logList.removeChild(logList.lastChild);
  }

  function setPill(el, online, onlineText, offlineText) {
    el.classList.toggle("online", online);
    el.classList.toggle("offline", !online);
    el.textContent = online ? onlineText : offlineText;
  }

  function drawChart(values) {
    const canvas = $("#latency-chart");
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    const w = canvas.width;
    const h = canvas.height;
    ctx.clearRect(0, 0, w, h);
    ctx.strokeStyle = "#2a403c";
    ctx.beginPath();
    for (let y = 0; y <= h; y += 28) {
      ctx.moveTo(0, y);
      ctx.lineTo(w, y);
    }
    ctx.stroke();
    if (!values.length) return;
    const max = Math.max(10, ...values);
    ctx.strokeStyle = "#7dd3c0";
    ctx.lineWidth = 2;
    ctx.beginPath();
    values.forEach((v, i) => {
      const x = (i / Math.max(1, values.length - 1)) * (w - 8) + 4;
      const y = h - 8 - (v / max) * (h - 16);
      if (i === 0) ctx.moveTo(x, y);
      else ctx.lineTo(x, y);
    });
    ctx.stroke();
    ctx.fillStyle = "#e8b86d";
    ctx.font = "11px IBM Plex Mono";
    ctx.fillText(`n=${values.length}  max=${max.toFixed(1)}ms`, 8, 14);
  }

  function applyTelemetry(tel) {
    if (!tel) return;
    const sqi = tel.sync_quality_index ?? 0;
    const p50 = tel.command_latency_ms?.p50;
    const p95 = tel.command_latency_ms?.p95;
    const skew = tel.protocol_metrics?.last_pair_skew_ms;
    $("#r-sqi").textContent = `${Number(sqi).toFixed(1)}`;
    $("#r-p50").textContent = p50 == null ? "—" : `${p50} ms`;
    $("#r-p95").textContent = p95 == null ? "—" : `${p95} ms`;
    $("#r-skew").textContent = skew == null ? "—" : `${Number(skew).toFixed(1)} ms`;
    $("#sqi-status").textContent = `SQI ${Number(sqi).toFixed(0)}`;

    const points = (tel.series_tail || [])
      .filter((s) => s.kind === "command" && typeof s.latency_ms === "number")
      .map((s) => s.latency_ms);
    if (points.length) {
      latencySeries = points.slice(-60);
      drawChart(latencySeries);
    }
  }

  function applyState(state, telemetry) {
    if (!state) return;
    const s = state.sensors || {};
    const a = state.actuators || {};
    const boards = state.boards || {};

    $("#m-temp").textContent = `${Number(s.temperature ?? 0).toFixed(1)}°C`;
    $("#m-hum").textContent = `${Number(s.humidity ?? 0).toFixed(0)}%`;
    $("#m-light").textContent = `${Number(s.light ?? 0).toFixed(0)}%`;
    $("#m-motion").textContent = s.motion ? "SIM" : "NÃO";

    $("#last-event").textContent = state.last_event || "—";
    const synced = boards.arduino?.sync && boards.raspberry?.sync;
    $("#sync-status").textContent = synced ? `SYNC OK #${state.sync_pulse ?? 0}` : "SYNC OFF";

    if (typeof state.sync_quality_index === "number") {
      $("#sqi-status").textContent = `SQI ${state.sync_quality_index.toFixed(0)}`;
      $("#r-sqi").textContent = state.sync_quality_index.toFixed(1);
    }
    if (state.pair_skew_ms != null) {
      $("#r-skew").textContent = `${Number(state.pair_skew_ms).toFixed(1)} ms`;
    }

    const salaOn = !!(a.relay && a.relay["1"]);
    const cozOn = !!(a.relay && a.relay["2"]);
    $("#bulb-sala").setAttribute("fill", salaOn ? "#ffe082" : "#3d4f4c");
    $("#bulb-sala").setAttribute("filter", salaOn ? "url(#glow)" : "");
    $("#bulb-cozinha").setAttribute("fill", cozOn ? "#ffe082" : "#3d4f4c");
    $("#bulb-cozinha").setAttribute("filter", cozOn ? "url(#glow)" : "");

    $("#led-indicator").setAttribute("fill", a.led ? "#7CFFB2" : "#35524e");
    $("#led-indicator").setAttribute("filter", a.led ? "url(#glow)" : "");
    $("#buzzer-indicator").setAttribute("fill", a.buzzer ? "#e07a5f" : "#35524e");

    $("#door-main-panel").classList.toggle("open", !!(a.door && a.door.main));
    $("#door-garage-panel").classList.toggle("open", !!(a.door && a.door.garage));

    const s1 = (a.servo && a.servo["porta-1"]) || 0;
    const s2 = (a.servo && a.servo["porta-2"]) || 0;
    const s3 = (a.servo && a.servo.arm) || 0;
    $("#servo-arm-1").setAttribute("transform", `rotate(${s1})`);
    $("#servo-arm-2").setAttribute("transform", `rotate(${s2})`);
    $("#servo-arm-3").setAttribute("transform", `rotate(${-s3})`);
    $("#servo-arm-slider").value = s3;
    $("#servo-arm-value").textContent = `${s3}°`;

    $("#motion-blob").setAttribute("opacity", s.motion ? "0.9" : "0.15");

    const arOnline = !!boards.arduino?.online;
    const piOnline = !!boards.raspberry?.online;
    $("#arduino-status-text").textContent = arOnline ? "ONLINE" : "OFFLINE";
    $("#raspberry-status-text").textContent = piOnline ? "ONLINE" : "OFFLINE";
    $("#arduino-pulse").setAttribute("fill", arOnline ? "#80cbc4" : "#555");
    $("#raspberry-pulse").setAttribute("fill", piOnline ? "#f48fb1" : "#555");
    $("#sync-line").setAttribute("opacity", synced ? "0.85" : "0.15");
    $("#sync-dot").style.display = synced ? "block" : "none";

    if (state.sync_pulse % 2 === 0) {
      $("#board-arduino").classList.remove("board-flash");
      void $("#board-arduino").offsetWidth;
      $("#board-arduino").classList.add("board-flash");
    } else {
      $("#board-raspberry").classList.remove("board-flash");
      void $("#board-raspberry").offsetWidth;
      $("#board-raspberry").classList.add("board-flash");
    }

    if (telemetry) applyTelemetry(telemetry);
  }

  function send(payload) {
    if (ws && ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify(payload));
      return;
    }
    const map = {
      led: "/api/led",
      buzzer: "/api/buzzer",
      relay: "/api/relay",
      servo: "/api/servo",
      door: "/api/door",
      simulate: "/api/simulate",
    };
    const url = map[payload.action];
    if (!url) return;
    const body = { ...payload };
    delete body.action;
    if (payload.action === "simulate") body.scenario = payload.scenario;
    fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    })
      .then((r) => r.json())
      .then((data) => {
        if (data.state) applyState(data.state);
        pushLog(data.scenario ? `Cenário: ${data.scenario}` : payload.action);
      });
  }

  function refreshTelemetry() {
    fetch("/api/research/telemetry")
      .then((r) => r.json())
      .then(applyTelemetry)
      .catch(() => {});
  }

  function pushExperiment(result) {
    const li = document.createElement("li");
    const id = result.experiment_id;
    li.innerHTML = `<strong>${result.name}</strong> · SQI ${result.metrics?.sync_quality_index ?? "—"} ·
      <a href="/api/research/experiments/${id}/export.csv" target="_blank">CSV</a> ·
      <a href="/api/research/experiments/${id}/export.json" target="_blank">JSON</a>`;
    expList.prepend(li);
  }

  function runExperiment(name) {
    pushLog(`Experimento iniciado: ${name}`);
    fetch("/api/research/experiments/run", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name, params: {} }),
    })
      .then((r) => r.json())
      .then((data) => {
        if (!data.ok) throw new Error(data.detail || "falha");
        pushExperiment(data.result);
        applyTelemetry(data.result.metrics);
        pushLog(`Experimento OK: ${name} (${data.result.experiment_id})`);
      })
      .catch((err) => pushLog(`Experimento falhou: ${err.message || err}`));
  }

  function connectWs() {
    const proto = location.protocol === "https:" ? "wss" : "ws";
    ws = new WebSocket(`${proto}://${location.host}/api/ws`);
    ws.onopen = () => {
      setPill($("#ws-status"), true, "WS online", "WS offline");
      pushLog("WebSocket conectado");
      clearTimeout(reconnectTimer);
    };
    ws.onclose = () => {
      setPill($("#ws-status"), false, "WS online", "WS offline");
      pushLog("WebSocket desconectado — reconectando…");
      reconnectTimer = setTimeout(connectWs, 1500);
    };
    ws.onerror = () => ws.close();
    ws.onmessage = (ev) => {
      try {
        const msg = JSON.parse(ev.data);
        if (msg.type === "state") {
          applyState(msg.data);
          if (msg.data?.last_event) pushLog(msg.data.last_event);
        }
      } catch (_) { /* ignore */ }
    };
  }

  document.querySelectorAll("button[data-action]").forEach((btn) => {
    btn.addEventListener("click", () => {
      const action = btn.dataset.action;
      const payload = { action };
      if (action === "led" || action === "buzzer") payload.on = btn.dataset.on === "true";
      if (action === "relay") {
        payload.channel = btn.dataset.channel;
        payload.on = btn.dataset.on === "true";
      }
      if (action === "door") {
        payload.door_id = btn.dataset.door;
        payload.open = btn.dataset.open === "true";
      }
      send(payload);
    });
  });

  document.querySelectorAll("button[data-scenario]").forEach((btn) => {
    btn.addEventListener("click", () => {
      send({ action: "simulate", scenario: btn.dataset.scenario });
      pushLog(`Simulação: ${btn.dataset.scenario}`);
    });
  });

  document.querySelectorAll("button[data-experiment]").forEach((btn) => {
    btn.addEventListener("click", () => runExperiment(btn.dataset.experiment));
  });

  let servoTimer;
  $("#servo-arm-slider").addEventListener("input", (e) => {
    const angle = Number(e.target.value);
    $("#servo-arm-value").textContent = `${angle}°`;
    clearTimeout(servoTimer);
    servoTimer = setTimeout(() => {
      send({ action: "servo", servo_id: "arm", angle });
    }, 80);
  });

  fetch("/api/status")
    .then((r) => r.json())
    .then((data) => applyState(data.state, data.telemetry))
    .catch(() => pushLog("Falha ao carregar status inicial"));

  fetch("/api/logs?limit=15")
    .then((r) => r.json())
    .then((rows) => {
      rows.reverse().forEach((row) => pushLog(`${row.device}: ${row.action} ${row.detail || ""}`));
    })
    .catch(() => {});

  connectWs();
  refreshTelemetry();
  setInterval(refreshTelemetry, 2500);
  drawChart([]);
})();

:root {
  --bg: #0b1211;
  --panel: #12201e;
  --ink: #e8f0ee;
  --muted: #8aa39c;
  --line: #2a403c;
  --accent: #7dd3c0;
  --amber: #e8b86d;
  --warn: #e07a5f;
  --arduino: #26a69a;
  --pi: #ec407a;
  --font-display: "Syne", sans-serif;
  --font-mono: "IBM Plex Mono", monospace;
}

* { box-sizing: border-box; }
html, body { margin: 0; min-height: 100%; }
body {
  color: var(--ink);
  font-family: var(--font-mono);
  background:
    radial-gradient(1000px 500px at 10% -10%, #1a3330 0%, transparent 55%),
    radial-gradient(800px 400px at 90% 0%, #2a1a24 0%, transparent 50%),
    linear-gradient(160deg, #0d1615, #0b1211 40%, #101818);
  overflow-x: hidden;
}

.noise {
  pointer-events: none;
  position: fixed;
  inset: 0;
  opacity: 0.05;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  z-index: 0;
}

.topbar, .layout { position: relative; z-index: 1; }

.topbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 1rem;
  padding: 1rem 1.5rem;
  border-bottom: 1px solid var(--line);
  backdrop-filter: blur(8px);
}

.brand { display: flex; align-items: center; gap: 0.9rem; }
.brand-mark {
  width: 14px; height: 42px; border-radius: 3px;
  background: linear-gradient(180deg, var(--accent), var(--amber));
  box-shadow: 0 0 18px rgba(125, 211, 192, 0.35);
}
.brand h1 {
  margin: 0;
  font-family: var(--font-display);
  font-size: 1.55rem;
  letter-spacing: -0.03em;
  font-weight: 800;
}
.brand p { margin: 0.1rem 0 0; color: var(--muted); font-size: 0.78rem; }

.top-meta { display: flex; flex-wrap: wrap; gap: 0.55rem; align-items: center; justify-content: flex-end; }
.pill {
  border: 1px solid var(--line);
  border-radius: 999px;
  padding: 0.28rem 0.7rem;
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}
.pill.offline { color: var(--warn); border-color: #6b3a32; }
.pill.online { color: var(--accent); border-color: #2f6b5f; }
.pill.sync { color: var(--amber); }
.event { color: var(--muted); font-size: 0.78rem; max-width: 280px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }

.layout {
  display: grid;
  grid-template-columns: 1.4fr 1fr;
  gap: 1rem;
  padding: 1rem 1.25rem 1.5rem;
  min-height: calc(100vh - 84px);
}

.stage {
  background: rgba(18, 32, 30, 0.85);
  border: 1px solid var(--line);
  border-radius: 18px;
  padding: 0.75rem;
  overflow: hidden;
}
.stage-grid {
  background-image:
    linear-gradient(rgba(125, 211, 192, 0.04) 1px, transparent 1px),
    linear-gradient(90deg, rgba(125, 211, 192, 0.04) 1px, transparent 1px);
  background-size: 28px 28px;
  border-radius: 12px;
  height: 100%;
  min-height: 520px;
}
#house-svg { width: 100%; height: 100%; display: block; }
.room-label { fill: #6f8f88; font-size: 12px; font-family: var(--font-mono); letter-spacing: 0.12em; }
.tiny { fill: #7f9a94; font-size: 10px; font-family: var(--font-mono); }

.door-panel { transform-origin: 0px 0px; transition: transform 0.7s cubic-bezier(0.22, 1, 0.36, 1); }
.door-panel.open { transform: rotate(-78deg); }
.garage-panel { transform-origin: 0px 0px; transition: transform 0.8s cubic-bezier(0.22, 1, 0.36, 1); }
.garage-panel.open { transform: translateY(-100px); }

.panel {
  display: flex;
  flex-direction: column;
  gap: 0.85rem;
  min-height: 0;
}

.metrics {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.65rem;
}
.metrics article {
  background: var(--panel);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 0.85rem 0.95rem;
}
.metrics span { display: block; color: var(--muted); font-size: 0.72rem; text-transform: uppercase; letter-spacing: 0.06em; }
.metrics strong {
  display: block;
  margin-top: 0.35rem;
  font-family: var(--font-display);
  font-size: 1.55rem;
  letter-spacing: -0.03em;
}

.controls, .scenarios, .logs {
  background: var(--panel);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 0.9rem 1rem;
}
h2 {
  margin: 0 0 0.75rem;
  font-family: var(--font-display);
  font-size: 1rem;
  letter-spacing: -0.02em;
}

.btn-row { display: flex; flex-wrap: wrap; gap: 0.45rem; margin-bottom: 0.55rem; }
button {
  appearance: none;
  border: 1px solid #3a5f58;
  background: linear-gradient(180deg, #1d3531, #16302c);
  color: var(--ink);
  font-family: var(--font-mono);
  font-size: 0.72rem;
  padding: 0.55rem 0.7rem;
  border-radius: 10px;
  cursor: pointer;
  transition: transform 0.15s ease, border-color 0.15s ease, background 0.15s ease;
}
button:hover { transform: translateY(-1px); border-color: var(--accent); }
button:active { transform: translateY(0); }
button.ghost { background: transparent; color: var(--muted); }
button.warn { border-color: #7a4035; color: #f0b4a4; background: linear-gradient(180deg, #3a221e, #2a1714); }

.slider-label {
  display: grid;
  grid-template-columns: 1fr auto;
  gap: 0.35rem 0.75rem;
  align-items: center;
  color: var(--muted);
  font-size: 0.75rem;
  margin-top: 0.4rem;
}
.slider-label input { grid-column: 1 / -1; accent-color: var(--accent); }

.logs { flex: 1; min-height: 160px; display: flex; flex-direction: column; }
#log-list {
  list-style: none;
  margin: 0;
  padding: 0;
  overflow: auto;
  max-height: 220px;
}
#log-list li {
  border-top: 1px dashed var(--line);
  padding: 0.45rem 0;
  font-size: 0.72rem;
  color: var(--muted);
}
#log-list li strong { color: var(--amber); font-weight: 600; }

.research {
  background: var(--panel);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 0.9rem 1rem;
}
.research-lead {
  margin: -0.35rem 0 0.75rem;
  color: var(--muted);
  font-size: 0.72rem;
}
.research-metrics {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.5rem;
  margin-bottom: 0.65rem;
}
.research-metrics article {
  border: 1px solid var(--line);
  border-radius: 10px;
  padding: 0.55rem 0.65rem;
}
.research-metrics span {
  display: block;
  color: var(--muted);
  font-size: 0.65rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}
.research-metrics strong {
  font-family: var(--font-display);
  font-size: 1.15rem;
}
#latency-chart {
  width: 100%;
  height: 120px;
  border: 1px solid var(--line);
  border-radius: 10px;
  background: #0d1716;
  margin-bottom: 0.65rem;
}
.link-btn {
  display: inline-block;
  text-decoration: none;
  border: 1px solid #3a5f58;
  background: linear-gradient(180deg, #1d3531, #16302c);
  color: var(--ink);
  font-family: var(--font-mono);
  font-size: 0.72rem;
  padding: 0.55rem 0.7rem;
  border-radius: 10px;
}
.link-btn.ghost { background: transparent; color: var(--muted); }
#exp-list {
  list-style: none;
  margin: 0.4rem 0 0;
  padding: 0;
  max-height: 120px;
  overflow: auto;
}
#exp-list li {
  border-top: 1px dashed var(--line);
  padding: 0.4rem 0;
  font-size: 0.68rem;
  color: var(--muted);
}
#exp-list a { color: var(--accent); }

.board-flash { animation: flash 0.45s ease; }
@keyframes flash {
  0% { filter: brightness(1); }
  40% { filter: brightness(1.55); }
  100% { filter: brightness(1); }
}

@media (max-width: 980px) {
  .layout { grid-template-columns: 1fr; }
  .topbar { flex-direction: column; align-items: flex-start; }
  .stage-grid { min-height: 420px; }
}

package smarthome;

import javax.swing.BorderFactory;
import javax.swing.JButton;
import javax.swing.JFrame;
import javax.swing.JLabel;
import javax.swing.JPanel;
import javax.swing.JScrollPane;
import javax.swing.JTextArea;
import javax.swing.SwingUtilities;
import javax.swing.SwingWorker;
import javax.swing.Timer;
import java.awt.BorderLayout;
import java.awt.FlowLayout;
import java.awt.Font;
import java.awt.GridLayout;

/**
 * Dashboard desktop Java (Swing) — controla a mesma API do simulador web.
 * Execute com o servidor Python rodando em http://127.0.0.1:8000
 */
public class Dashboard extends JFrame {
    private final ApiClient api = new ApiClient("http://127.0.0.1:8000");
    private final JLabel statusLabel = new JLabel("Conectando…");
    private final JTextArea logArea = new JTextArea(12, 48);

    public Dashboard() {
        super("SmartHome IoT — Java Dashboard");
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        setSize(720, 520);
        setLocationRelativeTo(null);

        logArea.setEditable(false);
        logArea.setFont(new Font(Font.MONOSPACED, Font.PLAIN, 12));

        JPanel top = new JPanel(new BorderLayout());
        top.setBorder(BorderFactory.createEmptyBorder(10, 10, 10, 10));
        top.add(statusLabel, BorderLayout.CENTER);

        JPanel buttons = new JPanel(new GridLayout(0, 3, 8, 8));
        buttons.setBorder(BorderFactory.createEmptyBorder(8, 10, 8, 10));
        addBtn(buttons, "LED ON", () -> api.postJson("/api/led", "{\"on\":true}"));
        addBtn(buttons, "LED OFF", () -> api.postJson("/api/led", "{\"on\":false}"));
        addBtn(buttons, "Buzzer", () -> api.postJson("/api/buzzer", "{\"on\":true}"));
        addBtn(buttons, "Abrir Porta", () -> api.postJson("/api/door", "{\"door_id\":\"main\",\"open\":true}"));
        addBtn(buttons, "Fechar Porta", () -> api.postJson("/api/door", "{\"door_id\":\"main\",\"open\":false}"));
        addBtn(buttons, "Garagem", () -> api.postJson("/api/door", "{\"door_id\":\"garage\",\"open\":true}"));
        addBtn(buttons, "Relé Sala", () -> api.postJson("/api/relay", "{\"channel\":\"1\",\"on\":true}"));
        addBtn(buttons, "Cenário Welcome", () -> api.postJson("/api/simulate", "{\"scenario\":\"welcome\"}"));
        addBtn(buttons, "Teste Sync", () -> api.postJson("/api/simulate", "{\"scenario\":\"sync_test\"}"));
        addBtn(buttons, "Atualizar", () -> api.get("/api/status"));
        addBtn(buttons, "Modo Noite", () -> api.postJson("/api/simulate", "{\"scenario\":\"night\"}"));
        addBtn(buttons, "Alarme", () -> api.postJson("/api/simulate", "{\"scenario\":\"alarm\"}"));

        JPanel south = new JPanel(new FlowLayout(FlowLayout.LEFT));
        south.add(new JLabel("Logs / Status bruto:"));

        add(top, BorderLayout.NORTH);
        add(buttons, BorderLayout.CENTER);
        add(new JScrollPane(logArea), BorderLayout.SOUTH);

        Timer timer = new Timer(2000, e -> refreshStatus());
        timer.start();
        refreshStatus();
    }

    private void addBtn(JPanel panel, String title, ThrowingRunnable action) {
        JButton btn = new JButton(title);
        btn.addActionListener(e -> runAsync(title, action));
        panel.add(btn);
    }

    private void runAsync(String title, ThrowingRunnable action) {
        new SwingWorker<String, Void>() {
            @Override
            protected String doInBackground() throws Exception {
                return action.run();
            }

            @Override
            protected void done() {
                try {
                    append(title + " → OK\n" + get());
                    refreshStatus();
                } catch (Exception ex) {
                    append(title + " → ERRO: " + ex.getMessage());
                }
            }
        }.execute();
    }

    private void refreshStatus() {
        new SwingWorker<String, Void>() {
            @Override
            protected String doInBackground() throws Exception {
                return api.get("/api/status");
            }

            @Override
            protected void done() {
                try {
                    String body = get();
                    statusLabel.setText("API online — veja detalhes no painel inferior");
                    if (logArea.getText().length() < 20) {
                        append(body);
                    }
                } catch (Exception ex) {
                    statusLabel.setText("API offline: " + ex.getMessage());
                }
            }
        }.execute();
    }

    private void append(String text) {
        logArea.append(text + "\n\n");
        logArea.setCaretPosition(logArea.getDocument().getLength());
    }

    @FunctionalInterface
    interface ThrowingRunnable {
        String run() throws Exception;
    }

    public static void main(String[] args) {
        SwingUtilities.invokeLater(() -> new Dashboard().setVisible(true));
    }
}
